#include "bch_segmented/bch15_lookup_table.hpp"
#include "common/sha256.hpp"
#include <sstream>
namespace scl::bch::segmented { SyndromeTable buildBch15SyndromeTable(){SyndromeTable t;for(unsigned p=0;p<15;++p){common::BitVector e(15,0U);e[p]=1U;t.entries[p]={syndromeValue(computeBch15Syndrome(e)),p,e};}std::ostringstream c;c<<"codeName=BCH(15,11,1)\nn=15\nk=11\nt=1\ngeneratorPolynomial=x^4+x+1\nbitOrderVersion=BCH01_x14_to_x0_v1\nsyndromeOrder=x3_x2_x1_x0\ntableVersion=bch15_syndrome_v1\n";for(const auto&e:t.entries){c<<"syndromeBits=";for(auto b:computeBch15Syndrome(e.errorPattern))c<<static_cast<unsigned>(b);c<<",syndromeValue="<<e.syndrome<<",errorPosition="<<e.errorPosition<<",errorPattern=";for(auto b:e.errorPattern)c<<static_cast<unsigned>(b);c<<'\n';}t.hash=common::sha256Hex(c.str());return t;} int lookupErrorPosition(const SyndromeTable& t,unsigned s){if(s==0U)return -1;for(const auto& e:t.entries)if(e.syndrome==s)return static_cast<int>(e.errorPosition);return -1;}}
